previewCss:
.darma-loader-darma-custom-091 {
  width: 40px;
  aspect-ratio: 1;
  display: grid;
}
.darma-loader-darma-custom-091::before,
.darma-loader-darma-custom-091::after {
  content: "";
  grid-area: 1/1;
  background: #25b09b;
  clip-path: polygon(0 0,50% 50%, 0 100%);
  animation: darma-loader-darma-custom-091-l11 2s infinite;
}
.darma-loader-darma-custom-091::after {
  animation-delay: -1.5s;
  --s:90deg;
}
@keyframes darma-loader-darma-custom-091-l11 {
    0%,12.5%    {transform:rotate(var(--s,0deg)) rotate(0deg)}
    37.5%,62.5% {transform:rotate(var(--s,0deg)) rotate(-180deg)}
    87.5%,100%  {transform:rotate(var(--s,0deg)) rotate(-360deg)}
}

